vector<int> perm(int n){
    vector<int> s(n),t(n),ans(n,-1);
    vector<bool> vis(n);int pos0=n-1;
    for(int i=0;i<n-1;i++){
        s[i]=query(i+1,n-1);
        if(s[i]==0){
            pos0=i;
            for(int j=n-1;j>i;j--)
                t[j]=query(0,j-1);
            break;
        }
    }
    vis[0]=1,ans[pos0]=0;
    vis[s[0]]=1,ans[0]=s[0];
    vis[t[n-1]]=1,ans[n-1]=t[n-1];
    for(int i=1;i<n-1;i++){
        if(s[i]!=s[i-1])ans[i]=s[i],vis[s[i]]=1;
        if(t[i]!=t[i+1])ans[i]=t[i],vis[t[i]]=1;
    }
    int l=0,r=n-1;
    for(int x=n-1;x>0;x--){
        if(vis[x])continue;
        while(l<pos0&&ans[l]>=0)l++;
        while(r>pos0&&ans[r]>=0)r--;
        int id=(s[l]>t[r]?l:r);
        ans[id]=x,vis[x]=1;
    }
    return ans;
}
